  1	import * as React from 'react';
  2	import { USERS_CREATE_PAGE_PATH } from '@odf/core/constants/s3-iam';
  3	import { ODF_ADMIN } from '@odf/core/features';
  4	import { IamUserCrFormat, S3ProviderType } from '@odf/core/types';
  5	import { useRefresh } from '@odf/shared/hooks';
  6	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  7	import { getValidFilteredData } from '@odf/shared/utils';
  8	import {
  9	  ListPageBody,
 10	  ListPageCreateLink,
 11	  ListPageFilter,
 12	  ListPageHeader,
 13	  useFlag,
 14	  useModal,
 15	  useListPageFilter,
 16	} from '@openshift-console/dynamic-plugin-sdk';
 17	import { Button, ButtonVariant, Flex, FlexItem } from '@patternfly/react-core';
 18	import { SyncAltIcon } from '@patternfly/react-icons';
 19	import { ActionsColumn } from '@patternfly/react-table';
 20	import {
 21	  getAcountBadge,
 22	  getAccountActionsItems,
 23	} from '../../s3-browser/buckets-list-page/bucketsListPage';
 24	import { ClientType } from '../../s3-common/types';
 25	import { IamContext, IamProvider } from '../iam-context';
 26	import { UsersListTable } from './UsersListTable';
 27	import { UsersPagination } from './UsersPagination';
 28	
 29	type UsersInfo = [IamUserCrFormat[], boolean, any];
 30	
 31	type UsersListPageBodyProps = {
 32	  usersInfo: UsersInfo;
 33	  setUsersInfo: React.Dispatch<React.SetStateAction<UsersInfo>>;
 34	};
 35	
 36	const UsersListPageBody: React.FC<UsersListPageBodyProps> = ({
 37	  usersInfo,
 38	  setUsersInfo,
 39	}) => {
 40	  const { t } = useCustomTranslation();
 41	  const [fresh, triggerRefresh] = useRefresh();
 42	  const [users, loaded, loadError] = usersInfo;
 43	  const [allUsers, filteredUsers, onFilterChange] = useListPageFilter(users);
 44	  return (
 45	    <ListPageBody>
 46	      <Flex className="pf-v6-u-mt-md">
 47	        <Flex flex={{ default: 'flex_1' }}>
 48	          <FlexItem className="pf-v6-u-mr-md">
 49	            <ListPageFilter
 50	              loaded={true}
 51	              hideLabelFilter={true}
 52	              nameFilterPlaceholder={t('Find by accountname')}
 53	              data={getValidFilteredData(allUsers)}
 54	              onFilterChange={onFilterChange}
 55	            />
 56	          </FlexItem>
 57	          <FlexItem>
 58	            <Button
 59	              data-test="users-list-sync-button"
 60	              variant={ButtonVariant.plain}
 61	              onClick={triggerRefresh}
 62	              isDisabled={!fresh}
 63	            >
 64	              <SyncAltIcon />
 65	            </Button>
 66	          </FlexItem>
 67	        </Flex>
 68	        <Flex>
 69	          <FlexItem>
 70	            {fresh && <UsersPagination setUsersInfo={setUsersInfo} />}
 71	          </FlexItem>
 72	        </Flex>
 73	      </Flex>
 74	      {fresh && (
 75	        <UsersListTable
 76	          allUsers={users}
 77	          filteredUsers={filteredUsers}
 78	          loaded={loaded}
 79	          error={loadError}
 80	          triggerRefresh={triggerRefresh}
 81	        />
 82	      )}
 83	    </ListPageBody>
 84	  );
 85	};
 86	
 87	const UsersListPageContent: React.FC = () => {
 88	  const { t } = useCustomTranslation();
 89	
 90	  const [usersInfo, setUsersInfo] = React.useState<UsersInfo>([
 91	    [],
 92	    false,
 93	    undefined,
 94	  ]);
 95	
 96	  const isAdmin = useFlag(ODF_ADMIN);
 97	  const { logout, setSecretRef } = React.useContext(IamContext);
 98	  const launcher = useModal();
 99	
100	  return (
101	    <>
102	      <ListPageHeader
103	        title={t('IAM user')}
104	        {...(!isAdmin ? { badge: getAcountBadge(t) } : {})}
105	      >
106	        <ListPageCreateLink to={USERS_CREATE_PAGE_PATH}>
107	          {t('Create IAM user')}
108	        </ListPageCreateLink>
109	        {!isAdmin && (
110	          <ActionsColumn
111	            items={getAccountActionsItems(
112	              t,
113	              launcher,
114	              S3ProviderType.Noobaa,
115	              logout,
116	              setSecretRef,
117	              ClientType.IAM
118	            )}
119	          />
120	        )}
121	      </ListPageHeader>
122	      <div className="pf-v6-u-ml-lg pf-v6-u-mr-lg text-muted">
123	        {t('IAM account is used to manage users, access keys and policies')}
124	      </div>
125	      <UsersListPageBody usersInfo={usersInfo} setUsersInfo={setUsersInfo} />
126	    </>
127	  );
128	};
129	
130	const UsersListPage: React.FC = () => {
131	  return (
132	    <IamProvider>
133	      <UsersListPageContent />
134	    </IamProvider>
135	  );
136	};
137	
138	export default UsersListPage;

